import React, { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { StatusesInterface } from "../../store/reducers/statuses-reducer";
import { ownerType } from "../../constants/types";
import { Search } from "../search/Search";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { isStatusFilterMatching } from "../../tools/isStatusFilterMatching";
// Импортируем наш компонент-парсер
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";
import { AdminDescription } from '../admin-editor/AdminDescription';
import "./StatusesTable.css";

interface TableRowProps extends StatusesInterface {
    reference?: HTMLElement | null;
}

export const StatusesTable: React.FC = () => {
    const queryClient = useQueryClient();
    const statuses = useQueryClient().getQueryData("statuses") as StatusesInterface[] | null;
    const { value } = useTypedSelector(store => store.searchReducer);
    const { t, i18n } = useTranslation();
    
    const [animatedClass, setAnimatedClass] = useState("");
    const [timeoutId, setTimeoutId] = useState<null | NodeJS.Timeout>(null);
    const [hiddenSections, setHiddenSections] = useState<Set<string>>(() => new Set());

    const lang = i18n.language.toUpperCase() as "RU" | "EN";
    const nameKey = `name${lang}` as keyof StatusesInterface;
    const descKey = `description${lang}` as keyof StatusesInterface;
    
    const [editConfig, setEditConfig] = useState<any[] | null>(null);
    const [selectedStatus, setSelectedStatus] = useState<any | null>(null);
    const [targetTable, setTargetTable] = useState<string>("sinner_statuses");
    const [isCreateMode, setIsCreateMode] = useState(false);

    const isAdmin = localStorage.getItem('isAdmin') === 'true';

    const getFieldsConfig = () => ([
        { label: 'ID', key: 'id', type: 'text' },
        { label: 'Name RU', key: 'nameRU', type: 'text' },
        { label: 'Name EN', key: 'nameEN', type: 'text' },
        { label: 'Description RU', key: 'descriptionRU', type: 'text' },
        { label: 'Description EN', key: 'descriptionEN', type: 'text' },
        { label: 'Owners', key: 'owners', type: 'text' },
        { label: 'Fuse Statuses', key: 'fuse_statuses', type: 'text' },
        { label: 'Tip', key: 'tip', type: 'text' }
    ]);

    const handleCreateClick = (table: string) => {
        setTargetTable(table);
        setIsCreateMode(true);
        setSelectedStatus({}); // Пустой объект
        setEditConfig(getFieldsConfig());
    };

    const handleStatusClick = (status: StatusesInterface) => {
        if (!isAdmin) return;

        // Логика определения таблицы:
        // Если в owners есть "anomaly", значит это таблица аномалий
        const table = status.owners?.includes("anomaly") 
            ? "anomaly_statuses" 
            : "sinner_statuses";

        setTargetTable(table);
        setIsCreateMode(false);
        setSelectedStatus(status);
        setEditConfig(getFieldsConfig());
    };

    const shouldShowStatus = (status: StatusesInterface) => {
        return !!(status.owners && status.owners.length > 0 && !status.owners.includes("passive"));
    };

    const filteredAndSortedData = useMemo(() => {
        if (!statuses) return [];
        return statuses
            .filter(status => 
                shouldShowStatus(status) && 
                isStatusFilterMatching(value, status)
            )
            .sort((a, b) => {
                const nameA = String(a[nameKey] || "").trim();
                const nameB = String(b[nameKey] || "").trim();
                return nameA.localeCompare(nameB, i18n.language, { 
                    sensitivity: 'base',
                    numeric: true 
                });
            });
    }, [statuses, value, i18n.language, nameKey]);

    const buttonsSections = [
        { owners: "sinner", header: t("StatusesTable.header.sinner") },
        { owners: "ego", header: t("StatusesTable.header.ego") },
        { owners: "sinner_story", header: t("StatusesTable.header.sinner_story") },
        { owners: "anomaly", header: t("StatusesTable.header.anomaly") },
        { owners: "md_gift", header: t("StatusesTable.header.md_gift") },
        { owners: "none", header: t("StatusesTable.header.none") },
    ];

    const handleScroll = (statusId: string, index: number) => {
        const status = filteredAndSortedData.find((s) => s.id === statusId) as TableRowProps;
        if (status?.reference) {
            status.reference.scrollIntoView({ behavior: 'smooth', block: 'center' });
            if (timeoutId) clearTimeout(timeoutId);
            setAnimatedClass(statusId);
            const newId = setTimeout(() => setAnimatedClass(""), 1000 + index * 5);
            setTimeoutId(newId);
        }
    };

    const toggleSection = (owners: string) => {
        setHiddenSections(current => {
            const next = new Set(current);
            next.has(owners) ? next.delete(owners) : next.add(owners);
            return next;
        });
    };

    return (
        <>
            <section className="statuses-search">
                <Search />
            </section>

            {buttonsSections.map((section, sIdx) => (
                <section key={sIdx} className="statuses-section">
                    <button
                        type="button"
                        className="statuses-section-toggle"
                        aria-expanded={!hiddenSections.has(section.owners)}
                        onClick={() => toggleSection(section.owners)}
                    >
                        <h2>{section.header}</h2>
                        <span aria-hidden="true">{hiddenSections.has(section.owners) ? "▾" : "▴"}</span>
                    </button>
                    {!hiddenSections.has(section.owners) && <article className="statuses-buttons">
                        {filteredAndSortedData.map((status, index) => {
                            if (status.owners?.includes(section.owners as ownerType)) {
                                return (
                                    <button key={status.id} onClick={() => handleScroll(status.id, index)}>
                                        <div className="status-tooltip">
                                            <SkillCoinDescription
                                                description={String(status[nameKey] || "")}
                                            />
                                        </div>
                                        <img 
                                            src={`${process.env.PUBLIC_URL}/images/tags/${status.id}.webp`} 
                                            alt={status.id} 
                                        />
                                    </button>
                                );
                            }
                            return null;
                        })}
                    </article>}
                </section>
            ))}

            {isAdmin && (
                <div className="admin-controls">
                    <button onClick={() => handleCreateClick('sinner_statuses')}>
                        + Создать в Sinner Statuses
                    </button>
                    <button onClick={() => handleCreateClick('anomaly_statuses')}>
                        + Создать в Anomaly Statuses
                    </button>
                </div>
            )}

            <table className="statuses-table">
                <thead>
                    <tr>
                        <th className="statuses-table-th-image">{t("StatusesTable.status")}</th>
                        <th className="statuses-table-th-name">{t("StatusesTable.name")}</th>
                        <th className="statuses-table-th-description">{t("StatusesTable.description")}</th>
                    </tr>
                </thead>
                
           
                <tbody>
                    {filteredAndSortedData.map((status) => {
                        const name = String(status[nameKey] || "");
                        const description = String(status[descKey] || "");

                        return (
                            <tr 
                                key={status.id} 
                                className={status.id === animatedClass ? "statuses-table-tr--active" : ""} 
                                ref={(el) => ((status as TableRowProps).reference = el)}
                                onClick={() => handleStatusClick(status)}
                                style={{ cursor: isAdmin ? 'pointer' : 'default' }}
                            >
                                <td className="statuses-table-th-image">
                                    <img src={`${process.env.PUBLIC_URL}/images/tags/${status.id}.webp`} alt={status.id} />
                                </td>
                                <td className="statuses-table-th-name">
                                    <SkillCoinDescription description={name} />
                                </td>
                                <td className="statuses-table-th-description">
                                    <div className="table-desc-context">
                                        <SkillCoinDescription description={description} />
                                    </div>
                                </td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>
            {editConfig && (
                <AdminDescription 
                    isNew={isCreateMode}
                    entityId={selectedStatus.id}
                    tableName={targetTable} 
                    fields={editConfig}
                    isOpen={!!editConfig}
                    onClose={() => setEditConfig(null)}
                    onUpdate={() => queryClient.invalidateQueries('statuses')}
                />
            )}
        </>
    );
};
