import React, { useState, useEffect, useMemo } from 'react';
import { useQueryClient } from "react-query";
import { useTranslation } from "react-i18next";
import { Link } from "react-router-dom";
import { SkillCoinDescription } from "../guides/text-formatter/SkillCoinDescription";
import { supabase } from '../../tools/supabaseClient';
import { IdentityInterface } from "../../store/reducers/ids-reducer";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { isIdentity } from "../../tools/isIdentity";
import './AdminEditor.css';

export const AdminEditor: React.FC = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [description, setDescription] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [entityType, setEntityType] = useState<"identities" | "ego">("identities");
  const [user, setUser] = useState<any>(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [, setLoading] = useState(true);
  // Состояние для сворачивания сайдбара
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const { i18n } = useTranslation();
  const queryClient = useQueryClient();
  
  const allIds = queryClient.getQueryData("identities") as IdentityInterface[] | null;
  const allEgo = queryClient.getQueryData("ego") as EGOInterface[] | null;

  const filteredList = useMemo(() => {
    const entities: Array<IdentityInterface | EGOInterface> = entityType === "identities"
      ? [...(allIds || [])]
      : [...(allEgo || [])];
    if (!searchQuery.trim()) return entities.sort((a, b) => b.releaseDate - a.releaseDate);
    const query = searchQuery.toLowerCase();
    return entities.filter(item =>
      item.nameRU?.toLowerCase().includes(query) || 
      item.nameEN?.toLowerCase().includes(query) ||
      item.imgUrl?.toLowerCase().includes(query)
    ).sort((a, b) => b.releaseDate - a.releaseDate);
  }, [allIds, allEgo, entityType, searchQuery]);

  // ... (логика auth и useEffect остается без изменений)
  const checkAdminStatus = async (currentUser: any) => {
    const roleInMetadata = currentUser?.app_metadata?.role === 'admin';
    if (roleInMetadata) { setIsAdmin(true); localStorage.setItem('isAdmin', 'true'); return; }
    const { data, error } = await supabase.from('profiles').select('is_admin').eq('id', currentUser.id).single();
    if (!error && data?.is_admin) { setIsAdmin(true); localStorage.setItem('isAdmin', 'true'); }
    else { localStorage.removeItem('isAdmin'); }
  };

  useEffect(() => {
    const initAuth = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) { setUser(session.user); await checkAdminStatus(session.user); }
      setLoading(false);
    };
    initAuth();
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (_, session) => {
      if (session?.user) { setUser(session.user); await checkAdminStatus(session.user); }
      else { setUser(null); setIsAdmin(false); localStorage.removeItem('isAdmin'); }
    });
    return () => subscription.unsubscribe();
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) { alert("Ошибка: " + error.message); setLoading(false); }
  };

  if (!user || !isAdmin) {
    return (
      <div className="auth-page-wrapper">
        <form onSubmit={handleLogin} className="auth-form">
          <h2>Admin Login</h2>
          <input className="auth-input" type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} required />
          <input className="auth-input" type="password" placeholder="Пароль" value={password} onChange={e => setPassword(e.target.value)} required />
          <button type="submit" className="submit-button">Войти</button>
        </form>
      </div>
    );
  }

  return (
    <div className={`admin-layout ${!isSidebarOpen ? 'sidebar-collapsed' : ''}`}> 
      <aside className="admin-sidebar">
        <button className="toggle-sidebar-btn" onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
          {isSidebarOpen ? "« Скрыть" : "»"}
        </button>

        {isSidebarOpen && (
          <>
            <div className="sidebar-header">
              <h3>Сущности ({filteredList.length})</h3>
              <input 
                type="text" 
                className="sidebar-search" 
                placeholder="Поиск..." 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
            <div className="sidebar-list">
              <div className="sidebar-type-switch" role="group" aria-label="Entity type">
                <button
                  type="button"
                  className={entityType === "identities" ? "active" : ""}
                  onClick={() => setEntityType("identities")}
                >
                  ID ({allIds?.length || 0})
                </button>
                <button
                  type="button"
                  className={entityType === "ego" ? "active" : ""}
                  onClick={() => setEntityType("ego")}
                >
                  E.G.O ({allEgo?.length || 0})
                </button>
              </div>
              {filteredList.map((entity, index) => {
                const isEgoEntity = !isIdentity(entity);
                const imgFolder = isEgoEntity ? "ego" : "identities";
                const linkPath = `/limbus/${i18n.language}/${imgFolder}/${entity.imgUrl}`;
                return (
                  <Link to={linkPath} key={`${imgFolder}-${entity.imgUrl}-${index}`} className="sidebar-item">
                     <div className="sidebar-img-frame"><img src={`${process.env.PUBLIC_URL}/images/${imgFolder}/${entity.imgUrl}.webp`} alt="" /></div>
                     <div className="sidebar-item-text">
                        <span className="sidebar-name">{entity.nameRU || entity.nameEN}</span>
                        <span className="sidebar-sub">{isEgoEntity ? "E.G.O" : "Identity"}</span>
                     </div>
                  </Link>
                );
              })}
            </div>
          </>
        )}
      </aside>

      <main className="admin-main-content">
        <div className="editor-section">
          <h3>Редактор описаний</h3>
          <textarea className="descriptionarea" value={description} onChange={(e) => setDescription(e.target.value)}></textarea>
        </div>
        <div className="preview-section">
          <h3>Предпросмотр:</h3>
          <div className="preview-grid">
            {description.split("|").map((desc, index) => desc.trim() !== "" && (
                <div key={index} className="descriptionContainer"><SkillCoinDescription description={desc.trim()} /></div>
            ))}
          </div>
        </div>
      </main>
    </div>
  );
};
