import React, { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useLocation } from 'react-router-dom';
import { mobileLayoutFrom } from '../../../constants/mobileLayoutFrom';
import { useTypedSelector } from '../../../hooks/useTypedSelector';
import { isEventFilterMatching } from '../../../tools/isEventFilterMatching';
import { MDEvent } from '../../../store/reducers/md-event-interface';
import { MDGift } from '../../../store/reducers/md-gift-interface';
import { Search } from '../../search/Search';
import { MDEventOption } from './option/MDEventOption';
import { createGiftList } from '../formatted-text-gift/MDGiftFormattedText';
import './MDEvents.css';

export const MDEvents: React.FC = () => {
    const events = useQueryClient().getQueryData("md-events") as MDEvent[] | null;
    const gifts = useQueryClient().getQueryData("md-gifts") as MDGift[] | null;
    const { t, i18n } = useTranslation();
    const { value } = useTypedSelector(store => store.searchReducer);
    const [animatedId, setAnimatedId] = useState<null | string>(null);
    const [animationTriggered, setAnimationTriggered] = useState<boolean>(false);
    
    // Состояние для выбранного события (модалки)
    const [selectedEvent, setSelectedEvent] = useState<MDEvent | null>(null);

    const eventId = new URLSearchParams(useLocation().search).get('id');

    const scrollToSection = (id: string) => {
        const section = document.getElementById(id);
        if (section) {
            const sectionRect = section.getBoundingClientRect();
            const offset = sectionRect.top + window.pageYOffset - (window.innerHeight / 2) + (sectionRect.height / 2);
            window.scrollTo({
                top: offset - ((mobileLayoutFrom >= window.innerWidth) ? 70 : 0),
                behavior: 'auto'
            });
        }
    };

    useEffect(() => {
        let timer: NodeJS.Timeout | null = null;
        if (eventId && !animationTriggered) {
            scrollToSection(eventId);
            setAnimatedId(eventId);
            timer = setTimeout(() => setAnimationTriggered(true), 2200);
        }
        return () => {
            if (timer) clearTimeout(timer);
        };
    }, [animationTriggered, eventId, events]);

    const filteredData = (events)
        ? events
            .reduce((acc: MDEvent[], curr) => {
                if (isEventFilterMatching(value, curr, i18n.language, gifts || []))
                    acc.push(curr);
                return acc;
            }, [])
            .sort((a, b) => {
                const numA = parseInt(a.id.replace(/\D/g, ''), 10) || 0;
                const numB = parseInt(b.id.replace(/\D/g, ''), 10) || 0;
                return numA - numB;
            })
        : [];

    return (
        <div className='MDEvents'>
            <h2> {t("MirrorDungeonNav.events")} ({filteredData.length})</h2>
            <Search />
            
            <div className="MDEvents-grid">
                {filteredData.map(e => {
                    const { id, abnoEN, abnoRU, choiceEN, choiceRU } = e;
                    const isAnimated = id === animatedId && !animationTriggered;

                    return (
                        <section
                            key={id} 
                            id={id}
                            className={`MDEvents-section MDEvents-section--clickable MDEvents-section--${isAnimated ? "animated" : "false"}`}
                            onClick={() => setSelectedEvent(e)}
                        >
                            <header>
                                <h3>{(i18n.language === "ru") ? abnoRU : abnoEN}</h3>
                                <img 
                                    src={`${process.env.PUBLIC_URL}/images/md-events/${id}.webp`} 
                                    alt={(i18n.language === "ru") ? abnoRU : abnoEN} 
                                />
                                <span className='MDEvents-ego-gifts-span'>
                                    {t("MDEventOption.gifts_list_header")}
                                </span>
                                <div className='MDEvents-ego-gifts-section'>
                                    {createGiftList((i18n.language === "ru") ? choiceRU.gift_id : choiceEN.gift_id, t)}
                                </div>
                            </header>
                        </section>
                    );
                })}
            </div>

            {/* Модальное окно (Тултип) */}
            {selectedEvent && (
                <div className="MDEvents-modal-overlay" onClick={() => setSelectedEvent(null)}>
                    <div className="MDEvents-modal-content" onClick={(e) => e.stopPropagation()}>
                        <button className="MDEvents-modal-close" onClick={() => setSelectedEvent(null)}>×</button>
                        <div className="MDEvents-modal-header">
                            <h3>{(i18n.language === "ru") ? selectedEvent.abnoRU : selectedEvent.abnoEN}</h3>
                        </div>
                        <div className="MDEvents-modal-body">
                             <MDEventOption option={(i18n.language === "ru") ? selectedEvent.choiceRU : selectedEvent.choiceEN} />
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};
