import React, { useState, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Link, useParams } from "react-router-dom";
import { useFetchChanLog } from "../../../api/useFetchByKeys"; 
import { ChanLogInterface } from "../../../store/reducers/chanlog-reducer";
import { SkillCoinDescription } from "../../guides/text-formatter/SkillCoinDescription";
import "./TierListNav.css";

const DescriptionSection: React.FC<{ title: string; content: string }> = ({ title, content }) => {
    const [isExpanded, setIsExpanded] = useState(false);

    return (
        <div className="description-section">
            <div className="section-header" onClick={() => setIsExpanded(!isExpanded)}>
                <div className="section-title-wrapper">
                    <SkillCoinDescription description={title} />
                </div>
                <button className="expand-toggle">
                    {isExpanded ? '▲' : '▼'}
                </button>
            </div>
            {isExpanded && (
                <div className="section-content">
                    <SkillCoinDescription description={content} />
                </div>
            )}
        </div>
    );
};

const ChangelogItem: React.FC<{ item: ChanLogInterface; language: string }> = ({ item, language }) => {
    const description = language === "ru" ? item.descriptionRu : item.descriptionEn;
    const sections: { title: string; content: string }[] = [];
    
    if (description) {
        const rawSections = description.split('|').filter(Boolean);
        for (let i = 0; i < rawSections.length; i += 2) {
            sections.push({
                title: rawSections[i] || "",
                content: rawSections[i + 1] || ""
            });
        }
    }

    return (
        <div className="changelog-item">
            <div className="changelog-date">{item.date}</div>
            <div className="changelog-sections">
                {sections.map((sec, idx) => (
                    <DescriptionSection key={idx} title={sec.title} content={sec.content} />
                ))}
            </div>
        </div>
    );
};

export const TierListNav: React.FC = () => {
    const { type } = useParams();
    const { t, i18n } = useTranslation();
    const [showChangelog, setShowChangelog] = useState(false);
    const { data: changelogData = [], isLoading } = useFetchChanLog();

    // Блокировка скролла body при открытом модальном окне
    useEffect(() => {
        if (showChangelog) {
            document.body.classList.add("no-scroll");
        } else {
            document.body.classList.remove("no-scroll");
        }
        return () => document.body.classList.remove("no-scroll");
    }, [showChangelog]);

    const sortedChangelog = [...(changelogData || [])].sort((a, b) => {
        const parse = (d: string) => {
            if (!d) return 0;
            return new Date(d.split('.').reverse().join('-')).getTime();
        };
        return parse(b.date) - parse(a.date);
    });

    return (
        <div className="tier-list-nav-container">
            <nav className="tier-list-nav">
                <ul>
                    {["identities", "ego"].map(path => (
                        <li key={path}>
                            <Link 
                                className={type === path ? "tier-list-nav--active" : ""} 
                                to={`/limbus/${i18n.language}/tierlist/${path}`}
                            >
                                {t(`TierListNav.${path}`)}
                            </Link>
                        </li>
                    ))}
                    <li>
                        <button onClick={() => setShowChangelog(true)} className="changelog-button">
                            {t("Changelog.headle")}
                        </button>
                    </li>
                </ul>
            </nav>

            {showChangelog && (
                <div className="changelog-backdrop" onClick={() => setShowChangelog(false)}>
                    <div className="changelog-panel" onClick={e => e.stopPropagation()}>
                        <div className="changelog-header">
                            <h3>{t("Changelog.headle")}</h3>
                            <button className="close-button" onClick={() => setShowChangelog(false)} aria-label="Close">×</button>
                        </div>
                        <div className="changelog-content">
                            {isLoading ? (
                                <p style={{ padding: "20px", textAlign: "center", color: "#aaa" }}>Loading...</p>
                            ) : sortedChangelog.length > 0 ? (
                                sortedChangelog.map((item, idx) => (
                                    <ChangelogItem key={item.ids || idx} item={item} language={i18n.language} />
                                ))
                            ) : (
                                <p style={{ padding: "20px", textAlign: "center", color: "#aaa" }}>No data found</p>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};
