import React, { useEffect, useRef } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { useDispatch } from "react-redux";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { EGOInterface } from "../../store/reducers/ego-reducer";
import { searchChangeTargetRefAction } from "../../store/reducers/search-reducer";
import { isFilterMatching } from "../../tools/isFilterMatching";
import { compareEntitiesByRarityAndDate } from "../../tools/compareEntitiesByRarityAndDate";
import { ItemEntity } from "../item-entity/ItemEntity";
import { ListSinnerBar } from "../list-sinner-bar/ListSinnerBar";
import { StatusesInterface } from "../../store/reducers/statuses-reducer";
import "./ListEgo.css";

export const ListEgo: React.FC = () => {
    const containerRef = useRef(null);
    const dispatch = useDispatch();
    const egoData = useQueryClient().getQueryData("ego") as EGOInterface[] | null;
    const statuses = useQueryClient().getQueryData('statuses') as StatusesInterface[];
    const filterState = useTypedSelector(state => state.filterReducer);
    const searchState = useTypedSelector(state => state.searchReducer);
    const { t, i18n } = useTranslation();

    useEffect(() => {
        searchChangeTargetRefAction(dispatch, containerRef);
    }, [dispatch]);

    const egoMap: { [key: string]: React.ReactNode[] } = {
        "new": [], "yi sang": [], "faust": [], "don quixote": [], "ryoshu": [],
        "mersault": [], "hong lu": [], "heathcliff": [], "ishmael": [], "rodion": [],
        "sinclair": [], "outis": [], "gregor": [],
    };

    let totalCount = 0;

    const checkStatusUnik = (entity: EGOInterface, activeTags: string[]) => {
        const unik = (entity as any).statusUnik;
        if (!unik) return { shouldHide: false, isForceShow: false };
        
        const [addPart, removePart] = unik.split('|').map((part: string) => part.trim());
        const statusesToAdd = addPart ? addPart.split('#').filter((s: string) => s.trim()).map((s: string) => s.trim().toLowerCase()) : [];
        const statusesToRemove = removePart ? removePart.split('#').filter((s: string) => s.trim()).map((s: string) => s.trim().toLowerCase()) : [];
        
        let isForceShow = false;
        for (const activeTag of activeTags) {
            const lowerTag = activeTag.toLowerCase();
            if (statusesToRemove.includes(lowerTag)) return { shouldHide: true, isForceShow: false };
            if (statusesToAdd.includes(lowerTag)) isForceShow = true;
        }
        return { shouldHide: false, isForceShow };
    };

    if (egoData) {
        const sortedEgo = [...egoData].sort(compareEntitiesByRarityAndDate);
        const activeTags = Object.keys(filterState.types.tags).filter(key => filterState.types.tags[key] === true);

        for (const currentEGO of sortedEgo) {
            const { isNew, imgUrl, sinner } = currentEGO;

            const { shouldHide, isForceShow } = checkStatusUnik(currentEGO, activeTags);
            if (shouldHide) continue;

            const isMatch = isFilterMatching(filterState, searchState, currentEGO, i18n.language, statuses);
            
            // Проверка: либо стандартный фильтр, либо ForceShow из statusUnik
            if (activeTags.length > 0) {
                if (!isMatch && !isForceShow) continue;
            } else if (!isMatch) continue;

            const element = <ItemEntity hideFooter={true} animationDelay={500} entity={currentEGO} key={imgUrl} />;
            
            if (!!(+isNew)) {
                egoMap.new.push(<ItemEntity hideFooter={true} animationDelay={500} entity={currentEGO} key={`${imgUrl}-new`} />);
            }
            if (sinner in egoMap) egoMap[sinner].push(element);
            totalCount++;
        }
    }

    return (
        <section ref={containerRef} className={"list-ego"}>
            <span className={"list-ego-span"}>{`${t("ListEgo.header")} (${totalCount})`}</span>
            {totalCount !== 0 ? (
                Object.entries(egoMap).map(([key, value]) => value.length > 0 && <ListSinnerBar key={key} sinner={key} data={value} />)
            ) : <p>{t("ListEgo.empty")}</p>}
        </section>
    );
};
