import { get, set } from "idb-keyval";
import { SUPABASE_URL, SUPABASE_ANON_KEY } from "../tools/supabaseClient";
import { CACHE_TIME, getCacheKey } from "./cache";
import { FETCH_CONFIG } from "./fetchConfig";

type CachedData = {
  data: unknown;
  timestamp: number;
};

const fetchJson = async (url: string) => {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Fetch error: ${response.status} ${response.statusText}`);
  }
  return response.json();
};

const fetchStatuses = async () => {
  const createUrl = (table: string) =>
    `${SUPABASE_URL}/rest/v1/${table}?select=*&apikey=${SUPABASE_ANON_KEY}`;

  const [sinnerStatuses, anomalyStatuses] = await Promise.all([
    fetchJson(createUrl("sinner_statuses")),
    fetchJson(createUrl("anomaly_statuses"))
  ]);

  const normalize = (items: any[]) => items.map((item) => ({
    ...item,
    nameEN: item.nameEN || item.nameen || "",
    owners: typeof item.owners === "string"
      ? item.owners.split(",").map((owner: string) => owner.trim())
      : (item.owners || [])
  }));

  return [...normalize(sinnerStatuses), ...normalize(anomalyStatuses)];
};

export const universalFetcher = async (key: string) => {
  const config = FETCH_CONFIG[key];
  if (!config && key !== "statuses") {
    throw new Error(`Unknown fetch key: ${key}`);
  }

  try {
    const cached = await get<CachedData>(getCacheKey(key));
    if (cached && Date.now() - cached.timestamp < CACHE_TIME) {
      return cached.data;
    }
  } catch (error) {
    console.warn("IDB read failed", error);
  }

  let resultData: any;
  if (key === "statuses") {
    resultData = await fetchStatuses();
  } else {
    const orderParam = config.order ? `&order=${config.order}` : "";
    const url = `${SUPABASE_URL}/rest/v1/${config.endpoint}?select=*${orderParam}&apikey=${SUPABASE_ANON_KEY}`;
    resultData = await fetchJson(url);
    if (config.validator) resultData = config.validator(resultData);
  }

  try {
    await set(getCacheKey(key), { data: resultData, timestamp: Date.now() });
  } catch (error) {
    console.warn("IDB write failed", error);
  }

  return resultData;
};
