import React, { useLayoutEffect, useRef, useState } from 'react';
import { TRAITS } from './traits';
import { useTranslation } from 'react-i18next';
import { useQueryClient } from 'react-query';
import { useParams } from 'react-router-dom';
import { SEOHelmet } from '../../pages/SEOHelmet';
import { IdentityInterface } from '../../store/reducers/ids-reducer';
import { LanguageDisclaimer } from '../language-disclaimer/LanguageDisclaimer';
import { EntityFullInfoIdentity } from './entity-full-info-identity/EntityFullInfoIdentity';
import { IdentitySkills } from './identity-skills/IdentitySkills';
import './EntityFullInfo.css';

export const EntityFullInfoIdentityMain = () => {
    const { identityId } = useParams();
    const { i18n, t } = useTranslation();

    const [showTraits, setShowTraits] = useState(false);
    const infoRef = useRef<HTMLDivElement>(null);

    const canViewTraits =
        localStorage.getItem('isReviewer') === 'true' ||
        localStorage.getItem('isAdmin') === 'true';

    const entities = useQueryClient().getQueryData(
        'identities'
    ) as IdentityInterface[];

    const maxLvlIdentity = 60;

    const entity = entities?.find(
        id => id.imgUrl === identityId
    );

    useLayoutEffect(() => {
        const info = infoRef.current;
        const entityInfo = info?.querySelector<HTMLElement>('.entityFullInfo-entity');
        const scroll = info?.querySelector<HTMLElement>('.entityFullInfo-skills-scroll');
        const synEgo = info?.querySelector<HTMLElement>('.s1yn-ego-container');
        if (!info || !entityInfo || !scroll || !synEgo) return;

        const syncHeight = () => {
            const entityRect = entityInfo.getBoundingClientRect();
            const scrollRect = scroll.getBoundingClientRect();
            const synEgoRect = synEgo.getBoundingClientRect();
            const availableHeight = scrollRect.top < synEgoRect.bottom
                ? synEgoRect.bottom - scrollRect.top
                : synEgoRect.bottom - entityRect.top;

            info.style.setProperty(
                '--entity-skills-scroll-height',
                `${Math.max(240, Math.round(availableHeight))}px`
            );
        };
        const observer = new ResizeObserver(syncHeight);
        observer.observe(entityInfo);
        observer.observe(synEgo);
        window.addEventListener('resize', syncHeight);
        syncHeight();

        return () => {
            observer.disconnect();
            window.removeEventListener('resize', syncHeight);
        };
    }, [entity]);

    if (!entity) return null;

    const statusUnik = (entity as any).statusUnik || '';

    const traits = entity.traits
        ? entity.traits
              .split(',')
              .map(trait => trait.trim())
              .filter(Boolean)
        : [];

    const nameKey =
        `name${i18n.language.toUpperCase()}` as keyof typeof entity;

    const rawName = entity[nameKey] as string;

    const sinnerId = (entity.sinner || '')
        .toLowerCase()
        .replace(/\s/g, '');

    const translatedSinner = t(`sinners.${sinnerId}`);

    const fullDisplayName = `[${rawName}] ${translatedSinner}`;

    return (
        <>
            <SEOHelmet
                title={`${fullDisplayName} | Great Limbus Library`}
                description={i18n.language === 'ru'
                    ? `${fullDisplayName} — личность в Limbus Company. Навыки, пассивки, характеристики, сопротивления и информация о механиках.`
                    : `${fullDisplayName} is a Limbus Company Identity. View skills, passives, stats, resistances, and core gameplay information.`}
            />

            <h1 className="entity-info-header">
                {fullDisplayName}

                <LanguageDisclaimer />

                {canViewTraits && traits.length > 0 && (
                    <div
                        className="entity-traits-dropdown"
                        onClick={() =>
                            setShowTraits(prev => !prev)
                        }
                    >
                        <span className="entity-traits-title">
                            {i18n.language === 'ru'
                                ? `Черты ${showTraits ? '▲' : '▼'}`
                                : `Traits ${showTraits ? '▲' : '▼'}`}
                        </span>

                        {showTraits && (
                            <div className="entity-traits-list">
                                {traits.map((trait, index) => {
                                    const traitInfo = TRAITS[trait];

                                    return (
                                        <span
                                            key={`${trait}-${index}`}
                                            className="entity-trait-tag"
                                        >
                                            {traitInfo
                                                ? traitInfo[
                                                      i18n.language === 'ru'
                                                          ? 'ru'
                                                          : 'en'
                                                  ]
                                                : trait}
                                        </span>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                )}
            </h1>

            <div ref={infoRef} className="entityFullInfo entityFullInfo--identity">
                <EntityFullInfoIdentity
                    identity={entity}
                    maxLvlIdentity={maxLvlIdentity}
                    statusUnik={statusUnik}
                />

                <IdentitySkills
                    identity={entity}
                    maxLvlIdentity={maxLvlIdentity}
                />
            </div>
        </>
    );
};
