import React, { useMemo, useState } from "react";
import { useTranslation } from "react-i18next";
import { useQueryClient } from "react-query";
import { sinType } from "../../../constants/types";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { EGOInterface } from "../../../store/reducers/ego-reducer";
import { IdentityInterface } from "../../../store/reducers/ids-reducer";
import { StatusesInterface } from "../../../store/reducers/statuses-reducer";
import { normalizeTbSin, SlotInterface } from "../../../store/reducers/tb-reducer";
import { getStatusesEntityList } from "../../../tools/getStatusesEntityList";
import { TbDamage } from "../tb-damage/TbDamage";
import "./TbSynergy.css";

const EGO_RARITIES = ["ZAYIN", "TETH", "HE", "WAW", "ALEPH"];
const TREMOR_SYNERGY_EGOS = ["ego_72", "ego_97"];
const MAIN_KEYWORDS = ["poise", "rupture", "charge", "sinking", "bleed", "burn", "tremor", "tremor-burst", "ammo", "bind", "haste", "bloodfeast", "tremor-scorch", "tremor-reverb", "tremor-hemorrhage", "tremor-fracture", "tremor-decay", "tremor-chain"];
const TREMOR_VARIANTS = ["tremor-scorch", "tremor-reverb", "tremor-hemorrhage", "tremor-fracture", "tremor-decay", "tremor-chain"];
const STATUS_LABELS: Record<string, string> = {
    poise: "Poise",
    rupture: "Rupture",
    charge: "Charge",
    sinking: "Sinking",
    bleed: "Bleed",
    burn: "Burn",
    tremor: "Tremor",
    "tremor-burst": "Tremor Burst",
    ammo: "Ammo",
    bind: "Bind",
    haste: "Haste",
    bloodfeast: "Bloodfeast",
    "tremor-scorch": "Tremor - Scorch",
    "tremor-reverb": "Tremor - Reverb",
    "tremor-hemorrhage": "Tremor - Hemorrhage",
    "tremor-fracture": "Tremor - Fracture",
    "tremor-decay": "Tremor - Decay",
    "tremor-chain": "Tremor - Chain",
};
const MAP_SIZE = 360;
const MAP_CENTER = MAP_SIZE / 2;
const MAP_RADIUS = 128;
type KeywordSource = "identity" | "ego";

type MemberSynergy = {
    index: number;
    name: string;
    sinner: string;
    imgUrl: string;
    keywords: string[];
    keywordSources: Record<string, KeywordSource[]>;
    directTargets: string[];
    supportPassives: PassiveInfo[];
    ego: EGOInterface[];
};

type PassiveInfo = {
    sins: sinType[];
    counts: number[];
    condition: string;
    description: string;
};

type PairSynergy = {
    a: MemberSynergy;
    b: MemberSynergy;
    keywords: string[];
    antiKeywords: string[];
    keywordSources: Record<string, KeywordSource[]>;
    directLinks: string[];
    recommendations: string[];
    score: number;
};

type MapNode = MemberSynergy & {
    x: number;
    y: number;
    score: number;
};

const splitList = (value?: string | null) => {
    if (!value) return [];
    return value
        .split(/[,\n;|]/)
        .map(item => item.trim())
        .filter(Boolean);
};

const splitStatusUnik = (value?: string | null) => {
    if (!value) return [];
    return value
        .split("|")[0]
        .split(/[,\n;]/)
        .map(item => item.trim())
        .filter(Boolean);
};

const normalizeStatus = (value: string) => value.toLowerCase().replace(/[^\p{L}0-9]+/gu, "");

const STATUS_ALIASES = Object.entries(STATUS_LABELS).reduce<Record<string, string>>((result, [key, label]) => {
    result[normalizeStatus(key)] = key;
    result[normalizeStatus(label)] = key;
    return result;
}, {
    tremorburst: "tremor-burst",
});

const toAllowedKeyword = (value: string) => STATUS_ALIASES[normalizeStatus(value)];

const getKeywordsFromText = (texts: (string | undefined | null)[]) => {
    return Object.keys(getStatusesEntityList(texts)).map(toAllowedKeyword).filter(Boolean);
};

const mergeKeywordSources = (...entries: Array<{ keywords: string[]; source: KeywordSource }>) => {
    const sources: Record<string, KeywordSource[]> = {};
    entries.forEach(entry => {
        entry.keywords.forEach(keyword => {
            sources[keyword] = Array.from(new Set([...(sources[keyword] || []), entry.source]));
        });
    });
    return sources;
};

const getIdentityKeywords = (identity: IdentityInterface) => {
    return sortKeywords([
        ...getKeywordsFromText([
            identity.descriptionCoinEN4,
            identity.descriptionPassive1EN,
            identity.descriptionPassive2EN,
        ]),
        ...splitStatusUnik(identity.statusUnik).map(toAllowedKeyword).filter(Boolean),
    ]);
};

const getSupportKeywords = (identity: IdentityInterface) => {
    return sortKeywords([
        ...getKeywordsFromText([
            identity.descriptionPassive2EN,
        ]),
        ...splitStatusUnik(identity.statusUnik).map(toAllowedKeyword).filter(Boolean),
    ]);
};

const getEgoKeywords = (ego: EGOInterface) => {
    return sortKeywords([
        ...getKeywordsFromText([
            ego.CoinEN4,
            ego.descriptionPassiveEN,
        ]),
        ...splitStatusUnik(ego.statusUnik).map(toAllowedKeyword).filter(Boolean),
    ]);
};

const getSlotEgos = (slot: SlotInterface) => {
    return EGO_RARITIES
        .map(rarity => slot.ego[rarity])
        .filter(Boolean) as EGOInterface[];
};

const normalize = (value: string) => value.toLowerCase().replace(/[^\p{L}0-9]+/gu, "");

type DirectCandidate = {
    key: string;
    label: string;
};

const targetMatchesCandidate = (target: string, candidate: DirectCandidate) => {
    const normalizedTarget = normalize(target);
    const normalizedKey = normalize(candidate.key);
    if (!normalizedTarget || !normalizedKey) return false;
    return normalizedTarget === normalizedKey || normalizedTarget.includes(normalizedKey) || normalizedKey.includes(normalizedTarget);
};

const getMemberCandidates = (member: MemberSynergy): DirectCandidate[] => {
    return [
        { key: member.imgUrl, label: member.sinner },
        { key: member.name, label: member.sinner },
        { key: member.sinner, label: member.sinner },
        ...member.ego.flatMap(ego => ([
            { key: ego.imgUrl, label: ego.nameEN || ego.nameRU || ego.imgUrl },
            { key: ego.nameEN, label: ego.nameEN || ego.imgUrl },
            { key: ego.nameRU, label: ego.nameRU || ego.imgUrl },
        ])),
    ].filter(candidate => candidate.key);
};

const getDirectLinks = (a: MemberSynergy, b: MemberSynergy) => {
    const bCandidates = getMemberCandidates(b);
    const aCandidates = getMemberCandidates(a);
    const aLinks = a.directTargets.flatMap(target => (
        bCandidates.filter(candidate => targetMatchesCandidate(target, candidate)).map(candidate => candidate.label)
    ));
    const bLinks = b.directTargets.flatMap(target => (
        aCandidates.filter(candidate => targetMatchesCandidate(target, candidate)).map(candidate => candidate.label)
    ));
    return Array.from(new Set([...aLinks, ...bLinks]));
};

const getMemberName = (identity: IdentityInterface) => {
    const title = identity.nameEN || identity.nameRU || identity.sinner;
    return title.replace(/\s+/g, " ").trim();
};

const getSinnerLabel = (sinner: string) => {
    return sinner
        .split(" ")
        .map(part => part.charAt(0).toUpperCase() + part.slice(1))
        .join(" ");
};

const getPassiveInfo = (identity: IdentityInterface, lang: string): PassiveInfo[] => {
    return [
        {
            sins: identity.sinPassive2 || [],
            counts: identity.countPassive2 || [],
            condition: identity.passive2Condition || "",
            description: lang === "ru" ? identity.descriptionPassive2RU : identity.descriptionPassive2EN,
        },
    ].filter(passive => passive.sins.length || passive.description || passive.condition);
};

const getPassiveConditionLabel = (condition: string) => {
    const normalized = condition.toLowerCase();
    if (normalized.includes("res")) return "Resonance";
    if (normalized.includes("own")) return "Owned";
    return condition || "Owned";
};

const getNodePosition = (nodeIndex: number, nodeCount: number) => {
    const angle = -Math.PI / 2 + (Math.PI * 2 * nodeIndex) / nodeCount;
    return {
        x: MAP_CENTER + Math.cos(angle) * MAP_RADIUS,
        y: MAP_CENTER + Math.sin(angle) * MAP_RADIUS,
    };
};

const sortKeywords = (keywords: string[]) => {
    return Array.from(new Set(keywords)).sort((a, b) => {
        const aIndex = MAIN_KEYWORDS.indexOf(a);
        const bIndex = MAIN_KEYWORDS.indexOf(b);
        if (aIndex === -1 && bIndex === -1) return a.localeCompare(b);
        if (aIndex === -1) return 1;
        if (bIndex === -1) return -1;
        return aIndex - bIndex;
    });
};

const getRecommendationLabel = (_lang: string) => "Recommended";

const DAMAGE_LABELS: Record<string, { en: string; ru: string }> = {
    slash: { en: "Slash", ru: "Slash" },
    pierce: { en: "Pierce", ru: "Pierce" },
    blunt: { en: "Blunt", ru: "Blunt" },
};

const getKeywordLabel = (keyword: string, lang: string, statuses: StatusesInterface[]) => {
    const status = statuses.find(item => item.id === keyword);
    if (status) return lang === "ru" ? status.nameRU || status.nameEN || keyword : status.nameEN || status.nameRU || keyword;
    const damageLabel = DAMAGE_LABELS[keyword];
    if (damageLabel) return lang === "ru" ? damageLabel.ru : damageLabel.en;
    return keyword;
};

const getDifferentTremorVariants = (a: MemberSynergy, b: MemberSynergy) => {
    const aVariants = a.keywords.filter(keyword => TREMOR_VARIANTS.includes(keyword));
    const bVariants = b.keywords.filter(keyword => TREMOR_VARIANTS.includes(keyword));
    return Array.from(new Set(aVariants.flatMap(aKeyword => (
        bVariants.filter(bKeyword => bKeyword !== aKeyword).map(bKeyword => `${aKeyword} + ${bKeyword}`)
    ))));
};

const getDifferentTremorVariantKeywords = (a: MemberSynergy, b: MemberSynergy) => {
    return getDifferentTremorVariants(a, b).flatMap(pair => pair.split(" + "));
};

const hasTremorSynergyEgo = (members: MemberSynergy[]) => {
    return members.some(member => member.ego.some(ego => TREMOR_SYNERGY_EGOS.includes(ego.imgUrl.toLowerCase())));
};

const getPairKeywordSources = (a: MemberSynergy, b: MemberSynergy, keywords: string[]) => {
    return keywords.reduce<Record<string, KeywordSource[]>>((result, keyword) => {
        result[keyword] = Array.from(new Set([
            ...(a.keywordSources[keyword] || []),
            ...(b.keywordSources[keyword] || []),
        ]));
        return result;
    }, {});
};

const getPairTooltip = (pair: PairSynergy, lang: string, statuses: StatusesInterface[]) => {
    const parts = [
        ...pair.keywords.map(keyword => {
            const label = getKeywordLabel(keyword, lang, statuses);
            return pair.keywordSources[keyword]?.includes("ego") ? `E.G.O ${label}` : label;
        }),
        ...pair.antiKeywords.map(keyword => `Anti: ${keyword.split(" + ").map(item => getKeywordLabel(item, lang, statuses)).join(" / ")}`),
        ...(pair.recommendations.length ? [`${getRecommendationLabel(lang)}: ${pair.recommendations.join(", ")}`] : []),
    ];
    return parts.join(" | ");
};

export const TbSynergy: React.FC = () => {
    const { slots } = useTypedSelector(store => store.tbReducer);
    const { t, i18n } = useTranslation();
    const statuses = (useQueryClient().getQueryData("statuses") as StatusesInterface[] | undefined) || [];
    const [hoveredPair, setHoveredPair] = useState<PairSynergy | null>(null);
    const [hoveredMemberIndex, setHoveredMemberIndex] = useState<number | null>(null);
    const lang = i18n.language;

    const { combatMembers, supportMembers } = useMemo(() => {
        return slots.reduce<{ combatMembers: MemberSynergy[]; supportMembers: MemberSynergy[] }>((result, slot, index) => {
            if (!slot.identity) return result;
            const egos = getSlotEgos(slot);
            const isSupport = slot.role === "support";
            const identityKeywords = isSupport ? getSupportKeywords(slot.identity) : getIdentityKeywords(slot.identity);
            const egoKeywords = isSupport ? [] : egos.flatMap(getEgoKeywords);
            const keywordSources = mergeKeywordSources(
                { keywords: identityKeywords, source: "identity" },
                { keywords: egoKeywords, source: "ego" },
            );
            const keywords = sortKeywords([...identityKeywords, ...egoKeywords]);

            const member: MemberSynergy = {
                index,
                name: getMemberName(slot.identity),
                sinner: getSinnerLabel(slot.identity.sinner),
                imgUrl: slot.identity.imgUrl,
                keywords,
                keywordSources,
                directTargets: isSupport ? [] : [
                    ...splitList(slot.identity.synEGO),
                    ...egos.flatMap(ego => splitList(ego.synIDS)),
                ],
                supportPassives: getPassiveInfo(slot.identity, lang),
                ego: isSupport ? [] : egos,
            };

            if (isSupport) result.supportMembers.push(member);
            else result.combatMembers.push(member);
            return result;
        }, { combatMembers: [], supportMembers: [] });
    }, [slots, lang]);

    const pairs = useMemo<PairSynergy[]>(() => {
        const result: PairSynergy[] = [];
        const shouldMergeTremorVariants = hasTremorSynergyEgo(combatMembers);
        for (let i = 0; i < combatMembers.length; i++) {
            for (let j = i + 1; j < combatMembers.length; j++) {
                const a = combatMembers[i];
                const b = combatMembers[j];
                const sharedKeywords = a.keywords.filter(keyword => b.keywords.includes(keyword));
                const tremorBridgeKeywords = shouldMergeTremorVariants ? getDifferentTremorVariantKeywords(a, b) : [];
                const keywords = sortKeywords([...sharedKeywords, ...tremorBridgeKeywords]);
                const antiKeywords = shouldMergeTremorVariants ? [] : getDifferentTremorVariants(a, b);
                const keywordSources = getPairKeywordSources(a, b, keywords);
                const directLinks = getDirectLinks(a, b);
                const recommendations = directLinks;
                const score = keywords.length * 2 + recommendations.length * 4 - antiKeywords.length * 2;
                if (score > 0 || antiKeywords.length > 0) result.push({ a, b, keywords, antiKeywords, keywordSources, directLinks, recommendations, score });
            }
        }
        return result.sort((a, b) => b.score - a.score);
    }, [combatMembers]);

    const nodes = useMemo<MapNode[]>(() => {
        return combatMembers.map((member, index) => {
            const position = getNodePosition(index, combatMembers.length);
            const score = pairs
                .filter(pair => pair.a.index === member.index || pair.b.index === member.index)
                .reduce((sum, pair) => sum + pair.score, 0);
            return { ...member, ...position, score };
        });
    }, [combatMembers, pairs]);

    const totalScore = pairs.reduce((sum, pair) => sum + pair.score, 0);
    const hoveredTooltip = hoveredPair ? getPairTooltip(hoveredPair, lang, statuses) : "";

    return (
        <section className="tb-synergy">
            <div className="tb-synergy-card tb-synergy-card--map">
                <div className="tb-synergy-card-header">
                    <h2 className="tb-synergy-title-tooltip">
                        {t("TbSynergy.map")}
                        <span className="tb-synergy-title-tooltip-content">{t("TbSynergy.mapTooltip")}</span>
                    </h2>
                    <span>{combatMembers.length}/12</span>
                </div>
                <div className="tb-synergy-map-shell">
                    {!!supportMembers.length && (
                        <div className="tb-synergy-support-wall">
                            {supportMembers.map(member => (
                                <div className="tb-synergy-support" key={member.index} title={member.name}>
                                    <img src={`${process.env.PUBLIC_URL}/images/identities/${member.imgUrl}.webp`} alt={member.name} />
                                    <span>{member.sinner}</span>
                                    <div className="tb-synergy-support-costs">
                                        {member.supportPassives.slice(0, 2).flatMap(passive => passive.sins.map((sin, index) => (
                                            <b key={`${member.index}-${sin}-${index}`}>
                                                <img src={`${process.env.PUBLIC_URL}/images/sins/${normalizeTbSin(sin)}.webp`} alt={sin} />
                                                {passive.counts[index] || passive.counts[0] || ""}
                                            </b>
                                        )))}
                                    </div>
                                    {member.supportPassives[0]?.condition && (
                                        <em className="tb-synergy-support-condition">
                                            {getPassiveConditionLabel(member.supportPassives[0].condition)}
                                        </em>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                    {combatMembers.length < 2 ? (
                        <p className="tb-synergy-empty">{t("TbSynergy.needMembers")}</p>
                    ) : (
                        <div className="tb-synergy-map" style={{ width: MAP_SIZE, height: MAP_SIZE }}>
                            <svg className="tb-synergy-map-lines" viewBox={`0 0 ${MAP_SIZE} ${MAP_SIZE}`}>
                                {pairs.map(pair => {
                                    const a = nodes.find(node => node.index === pair.a.index);
                                    const b = nodes.find(node => node.index === pair.b.index);
                                    if (!a || !b) return null;
                                    const hasRecommendation = pair.recommendations.length > 0;
                                    const hasAntiSynergy = pair.antiKeywords.length > 0;
                                    const isMemberLinkActive = hoveredMemberIndex !== null && (pair.a.index === hoveredMemberIndex || pair.b.index === hoveredMemberIndex);
                                    return (
                                        <g
                                            key={`${a.index}-${b.index}`}
                                            onMouseEnter={() => setHoveredPair(pair)}
                                            onMouseLeave={() => setHoveredPair(null)}
                                        >
                                            <line
                                                x1={a.x}
                                                y1={a.y}
                                                x2={b.x}
                                                y2={b.y}
                                                className={[
                                                    "tb-synergy-link",
                                                    hasRecommendation ? "tb-synergy-link--direct" : "",
                                                    hasAntiSynergy ? "tb-synergy-link--anti" : "",
                                                    isMemberLinkActive ? "tb-synergy-link--member-active" : "",
                                                ].join(" ")}
                                            />
                                            <line
                                                x1={a.x}
                                                y1={a.y}
                                                x2={b.x}
                                                y2={b.y}
                                                className="tb-synergy-link-hitbox"
                                            />
                                        </g>
                                    );
                                })}
                            </svg>
                            <div className="tb-synergy-map-total">{totalScore}</div>
                            {hoveredPair && (
                                <div className="tb-synergy-line-tooltip">
                                    {hoveredPair.a.sinner} - {hoveredPair.b.sinner}: {hoveredTooltip}
                                </div>
                            )}
                            {nodes.map(node => (
                                <div
                                    className="tb-synergy-node"
                                    key={node.index}
                                    style={{ left: node.x, top: node.y }}
                                    onMouseEnter={() => setHoveredMemberIndex(node.index)}
                                    onMouseLeave={() => setHoveredMemberIndex(null)}
                                >
                                    <img src={`${process.env.PUBLIC_URL}/images/identities/${node.imgUrl}.webp`} alt={node.name} />
                                    <b>{node.score}</b>
                                    <span>{node.sinner}</span>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            <div className="tb-synergy-card tb-synergy-card--damage">
                <TbDamage/>
            </div>
        </section>
    );
};
