import { useState, useEffect, useCallback } from 'react';
import { supabase } from '../tools/supabaseClient';

const TIER_MAP = ['C', 'B', 'A', 'S', 'SS', 'SSS'];

export const useEntityRating = (itemId: string | number) => {
    const [avgRating, setAvgRating] = useState<string>('-');
    const [userVote, setUserVote] = useState<number | null>(null);

    // Подтягиваем данные
    const fetchRating = useCallback(async () => {
        // 1. Получаем среднее значение напрямую из таблицы
        const { data, error } = await supabase
            .from('sunner_user_rank')
            .select('rating')
            .eq('item_id', itemId);

        if (error) {
            setAvgRating('-');
            return;
        }

        if (data && data.length > 0) {
            const sum = data.reduce((acc, curr) => acc + curr.rating, 0);
            const avg = Math.round(sum / data.length);
            // Ограничиваем индекс массивом TIER_MAP
            const tierIndex = Math.min(Math.max(avg - 1, 0), TIER_MAP.length - 1);
            setAvgRating(TIER_MAP[tierIndex]);
        }

        // 2. Узнаем, что поставил текущий юзер
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
            const { data: voteData } = await supabase
                .from('sunner_user_rank')
                .select('rating')
                .eq('item_id', itemId)
                .eq('user_id', user.id)
                .single();
            if (voteData) setUserVote(voteData.rating);
        }
    }, [itemId]);

    const handleVote = async (delta: number) => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return alert("Авторизуйтесь для оценки");

        // Если юзер уже голосовал, берем его старый голос или дефолт 3 (A)
        const currentRating = userVote || 3; 
        const newRating = Math.min(Math.max(currentRating + delta, 1), 6);

        const { error } = await supabase
            .from('sunner_user_rank')
            .upsert({ 
                item_id: itemId, 
                user_id: user.id, 
                rating: newRating 
            }, { onConflict: 'user_id, item_id' });

        if (!error) {
            setUserVote(newRating);
            fetchRating();
        }
    };

    useEffect(() => { void fetchRating(); }, [fetchRating]);

    return { avgRating, userVote, handleVote };
};
