export const decodeFormationCode = async (code: string, queryClient: QueryClient): Promise<SlotInterface[]> => {
    // 1. Декодирование строки
    const compressedBinaryString = atob(code);
    const compressedBytes = new Uint8Array(compressedBinaryString.length);
    for (let i = 0; i < compressedBinaryString.length; i++) compressedBytes[i] = compressedBinaryString.charCodeAt(i);
    const stream = new Blob([compressedBytes]).stream().pipeThrough(new (window as any).DecompressionStream("gzip"));
    const decompressedBuffer = await new Response(stream).arrayBuffer();
    const innerB64 = new TextDecoder().decode(decompressedBuffer);
    const binaryString = atob(innerB64);
    let bitString = "";
    for (let i = 0; i < binaryString.length; i++) bitString += binaryString.charCodeAt(i).toString(2).padStart(8, '0');

    // 2. Получаем данные из кэша один раз для скорости
    const allIdsCache = queryClient.getQueryData<IdentityInterface[]>("identities") || [];
    const allEgosCache = queryClient.getQueryData<EGOInterface[]>("ego") || [];

    let offset = 1;
    const newSlots: SlotInterface[] = [];

    for (let i = 0; i < 12; i++) {
        const sinnerId = i + 1;
        // Identity
        const persIdx = parseInt(bitString.substring(offset, offset + 7), 2);
        offset += 11; 
        let identity = null;
        if (persIdx > 0) {
            const imgUrl = `id_${ID_MAPS[sinnerId].ids[persIdx - 1]}`;
            identity = allIdsCache.find(id => id.imgUrl === imgUrl) || null;
        }

        // EGO
        const egoRarities = ["ZAYIN", "TETH", "HE", "WAW", "ALEPH"] as const;
        const egoContainer: any = {};
        
        for (const rarity of egoRarities) {
            const egoIdx = parseInt(bitString.substring(offset, offset + 7), 2);
            offset += 7;
            if (egoIdx > 0) {
                const imgUrl = `ego_${ID_MAPS[sinnerId].egos[egoIdx - 1]}`;
                const foundInCache = allEgosCache.find(e => e.imgUrl === imgUrl);
                
                egoContainer[rarity] = foundInCache;
            }
        }

        newSlots.push({ identity, ego: egoContainer });
    }
    return newSlots;
};
