import { useEffect, useState } from "react";
import { useDispatch } from "react-redux";
import { Link, useLocation } from "react-router-dom";
import { mobileLayoutFrom } from "../../constants/mobileLayoutFrom";
import { useTypedSelector } from "../../hooks/useTypedSelector";
import { leftMenuChangeLayoutAction } from "../../store/reducers/left-menu-reducer";

// Импорт ваших иконок
import { BoostySVG } from "../svg/BoostySVG"; 
import { DiscordIconSVG } from "../svg/DiscordIcon";

import "./TopMenu.css";

export const TopMenu = () => {
    const dispatch = useDispatch();
    const location = useLocation();

    useEffect(() => {
        if (window.innerWidth <= mobileLayoutFrom) leftMenuChangeLayoutAction(dispatch, true, false);
    }, [dispatch, location]);

    const [hasRendered, setHasRendered] = useState(false);
    useEffect(() => {
        setHasRendered(true);
    }, [dispatch]);

    const isMenuCollapsed = useTypedSelector(store => store.leftMenuReducer);

    return (
        <div className={`${hasRendered ? '' : 'first-render'} top-menu`}>
            <button
                type="button"
                onClick={() => leftMenuChangeLayoutAction(dispatch, !isMenuCollapsed, false)}
                className={`humburger-menu ${!isMenuCollapsed && "humburger-menu--expanded"}`}
                aria-label={isMenuCollapsed ? "Open navigation" : "Close navigation"}
                aria-expanded={!isMenuCollapsed}
            >
                <div className="line" />
            </button>

            <div className="top-menu-content-wrapper">
                <Link to="/limbus/">
                    <span className="website-title"> GREAT &#x20;<span> LIMBUS </span>LIBRARY</span>
                </Link>
                
                <div className="social-links-container">
                    <a href="https://boosty.to/gll-fun" target="_blank" rel="noreferrer" className="nav-social-btn boosty-btn">
                        <BoostySVG />
                    </a>
                    <a href="https://discord.gg/BGpmmqknWE" target="_blank" rel="noreferrer" className="nav-social-btn discord-btn">
                        <DiscordIconSVG />
                    </a>
                </div>
            </div>
        </div>
    );
}
