import React, { useEffect, useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useQuery } from "react-query";
import { EventInterface } from "../../../store/reducers/events_list-reducer";
import { supabase, SUPABASE_URL, SUPABASE_ANON_KEY } from "../../../tools/supabaseClient"; 
import "./EventsSection.css";

const MSK_OFFSET = 3;
const getMskFixedDate = (dateStr: any, targetMskHour: number): Date | null => {
  if (!dateStr) return null;
  if (typeof dateStr === 'string' && /^\d{2}\.\d{2}\.\d{4}$/.test(dateStr)) {
    const [day, month, year] = dateStr.split('.').map(Number);
    return new Date(Date.UTC(year, month - 1, day, targetMskHour - MSK_OFFSET));
  }
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return null;
  date.setUTCHours(targetMskHour - MSK_OFFSET, 0, 0, 0);
  return date;
};

const EventSector: React.FC<{ event: EventInterface; isAdmin: boolean }> = ({ event, isAdmin }) => {
  const { t } = useTranslation();
  const [now, setNow] = useState(new Date());
  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState<EventInterface>({ ...event });

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  const { startDate, endDate } = useMemo(() => ({
    startDate: getMskFixedDate(event.startDate, 6),
    endDate: getMskFixedDate(event.endDate, 4),
  }), [event.startDate, event.endDate]);

  const formatDiff = (ms: number) => {
    const d = Math.floor(ms / 86400000);
    const h = Math.floor((ms % 86400000) / 3600000);
    return `${d}${t("EventsSection.d")} ${h}${t("EventsSection.h")}`;
  };

  const renderTimerLabel = () => {
    if (!startDate) return t("EventsSection.startDateUnknown");
    const diffStart = startDate.getTime() - now.getTime();
    if (diffStart > 0) return formatDiff(diffStart);
    if (!endDate) return t("EventsSection.endDateUnknown");
    const diffEnd = endDate.getTime() - now.getTime();
    return diffEnd <= 0 ? t("EventsSection.eventEnded") : formatDiff(diffEnd);
  };

  if (isEditing && isAdmin) {
    return (
      <article className="event-sector-new editing-mode">
        <div className="edit-form-container">
          <input type="text" value={editData.nameRu ?? ""} onChange={e => setEditData({...editData, nameRu: e.target.value})} placeholder="Название RU" />
          <input type="text" value={editData.startDate ?? ""} onChange={e => setEditData({...editData, startDate: e.target.value})} placeholder="Старт DD.MM.YYYY" />
          <input type="text" value={editData.endDate ?? ""} onChange={e => setEditData({...editData, endDate: e.target.value})} placeholder="Конец DD.MM.YYYY" />
          <input type="text" value={editData.link ?? ""} onChange={e => setEditData({...editData, link: e.target.value})} placeholder="Ссылка" />
          <input type="text" value={editData.imgSrc ?? ""} onChange={e => setEditData({...editData, imgSrc: e.target.value})} placeholder="URL картинки" />
          <div className="edit-buttons">
            <button onClick={() => setIsEditing(false)}>OK</button>
            <button onClick={() => setIsEditing(false)}>X</button>
          </div>
        </div>
      </article>
    );
  }

  return (
    <article className="event-sector-new">
      {isAdmin && <button className="edit-trigger-btn" onClick={() => setIsEditing(true)}>⚙️</button>}
      <a href={event.link} target="_blank" rel="noopener noreferrer" className="event-card-link">
        <div className="event-image-wrapper">
          <img src={event.imgSrc} alt={event.nameEn} className="event-main-img" />
          <div className="event-overlay">
            <div className="event-timer-badge">
              <span className="timer-dot"></span>
              {renderTimerLabel()}
            </div>
            <div className="event-decor-dots">
              {[...Array(6)].map((_, i) => <span key={i} className="rarity-rhombus"></span>)}
            </div>
          </div>
        </div>
      </a>
    </article>
  );
};

export const EventsSection: React.FC = () => {
  const { data: events = [], isLoading } = useQuery("events", async () => {
    const url = `${SUPABASE_URL}/rest/v1/events?select=*&apikey=${SUPABASE_ANON_KEY}`;
    const response = await fetch(url);
    return response.json();
  }, { staleTime: 900000 });

  const [isAdmin, setIsAdmin] = useState(false);
  const { t } = useTranslation();

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session) {
        supabase.from('profiles').select('is_admin').eq('id', session.user.id).single()
          .then(({ data }) => setIsAdmin(!!data?.is_admin));
      }
    });
  }, []);

  if (isLoading) return <div className="loading-shimmer">{t("EventsSection.loading")}</div>;

  return (
    <section className="events-section">
      <h2 className="new-entity">{t("EventsSection.header")}</h2>
      {/* Добавлена обертка-контейнер для управления скроллом */}
      <div className="events-slider-wrapper">
        <div className="events-grid-layout">
          {events.map((event: any) => (
            <EventSector key={event.id} event={event} isAdmin={isAdmin} />
          ))}
        </div>
      </div>
    </section>
  );
};

export default EventsSection;
