import React, { useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { useDispatch } from "react-redux";
import { useQueryClient } from "react-query";
import { get, set } from "idb-keyval"; // Импортируем для работы с БД
import useHover from "../../../hooks/useHover";
import { useTypedSelector } from "../../../hooks/useTypedSelector";
import { 
    tbResetAllAction, 
    tbSetSlotsAction
} from "../../../store/reducers/tb-reducer";
import { ArrowLeftSVG } from "../../svg/ArrowLeft";
import { ArrowRightSVG } from "../../svg/ArrowRight";
import { XMarkSVG } from "../../svg/XMark";
import { Toggle } from "../../toggle/Toggle";
import { TbSlot } from "./tb-slot/TbSlot";
import { decodeFormationCode, ID_MAPS } from "./tb-utils"; 
import "./TbSlots.css";

const PRESETS_DB_KEY = 'tb-presets-db'; // Ключ для базы данных

export const TbSlots = () => {
    const { slots } = useTypedSelector(store => store.tbReducer);
    const { t } = useTranslation();
    const dispatch = useDispatch();
    const queryClient = useQueryClient();
    const containerRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const timeoutRef = useRef<NodeJS.Timeout | null>(null);

    // Состояние пресетов теперь по умолчанию пустое
    const [presets, setPresets] = useState<any[]>([]);
    const [showPresets, setShowPresets] = useState(false);
    const [importCode, setImportCode] = useState("");
    const [layout, setLayout] = useState<"grid" | "line">(() => (localStorage.getItem("tb-layout") as any) || "line");
    const [isSymmetric, setIsSymmetric] = useState(() => localStorage.getItem("tb-slots-symmetric") === "true");
    const [animatedClass, setAnimatedClass] = useState(layout === "line" ? "tb-slots-container--flex" : "tb-slots-container--grid");
    
    const isHovering = useHover(containerRef);

    // 1. ЗАГРУЗКА ПРЕСЕТОВ ИЗ БД ПРИ СТАРТЕ
    useEffect(() => {
        const loadPresets = async () => {
            try {
                const savedPresets = await get(PRESETS_DB_KEY);
                if (savedPresets) setPresets(savedPresets);
            } catch (err) {
                console.error("Failed to load presets from IDB", err);
            }
        };
        loadPresets();
    }, []);

    // 2. АВТОМАТИЧЕСКОЕ СОХРАНЕНИЕ ПРИ ИЗМЕНЕНИИ ПРЕСЕТОВ
    useEffect(() => {
        if (presets.length > 0 || localStorage.getItem('tb-presets')) { 
            // Сохраняем в новую БД
            set(PRESETS_DB_KEY, presets);
            // Можно очистить старый localStorage, чтобы не занимал место
            localStorage.removeItem('tb-presets');
        }
    }, [presets]);

    const handleLayoutChange = () => {
        if (timeoutRef.current) clearTimeout(timeoutRef.current);
        setAnimatedClass(prev => `${prev} hidden`);
        const newLayout = layout === "grid" ? "line" : "grid";
        timeoutRef.current = setTimeout(() => {
            setAnimatedClass(newLayout === "line" ? "tb-slots-container--flex" : "tb-slots-container--grid");
        }, 500);
        setLayout(newLayout);
        localStorage.setItem("tb-layout", newLayout);
    };

    const handleSymmetryChange = () => {
        setIsSymmetric(prev => {
            const nextValue = !prev;
            localStorage.setItem("tb-slots-symmetric", String(nextValue));
            return nextValue;
        });
    };

    const handleDownload = async () => {
        const getMod = (sinnerId: number, type: 'ids' | 'egos', val: any) => {
            if (!val) return 0;
            const cleanId = typeof val === 'string' ? parseInt(val.replace(/^\D+/g, ''), 10) : val;
            const list = ID_MAPS[sinnerId]?.[type];
            return list ? list.indexOf(cleanId) + 1 : 0;
        };

        let bitString = "1"; 
        slots.forEach((slot, i) => {
            const sId = i + 1;
            bitString += getMod(sId, 'ids', slot.identity?.imgUrl).toString(2).padStart(7, '0');
            bitString += (1).toString(2).padStart(4, '0');
            const egoUrls = [slot.ego?.ZAYIN?.imgUrl, slot.ego?.TETH?.imgUrl, slot.ego?.HE?.imgUrl, slot.ego?.WAW?.imgUrl, slot.ego?.ALEPH?.imgUrl];
            egoUrls.forEach(url => bitString += getMod(sId, 'egos', url).toString(2).padStart(7, '0'));
        });

        while (bitString.length % 8 !== 0) bitString += "0";
        const bytes = new Uint8Array(bitString.length / 8);
        for (let i = 0; i < bitString.length; i += 8) bytes[i / 8] = parseInt(bitString.substring(i, i + 8), 2);

        const innerB64 = btoa(String.fromCharCode(...Array.from(bytes)));
        const stream = new Blob([innerB64]).stream().pipeThrough(new (window as any).CompressionStream("gzip"));
        const compressedBytes = new Uint8Array(await new Response(stream).arrayBuffer());
        const finalCode = btoa(String.fromCharCode(...Array.from(compressedBytes)));
        
        try {
            await navigator.clipboard.writeText(finalCode);
            alert("Code copied to clipboard!");
        } catch (err) {
            const textArea = document.createElement('textarea');
            textArea.value = finalCode;
            document.body.appendChild(textArea);
            textArea.select();
            document.execCommand('copy');
            document.body.removeChild(textArea);
            alert("Code copied to clipboard!");
        }
    };

    const handleImportBtnClick = async () => {
        if (!importCode.trim()) return;
        try {
            const newSlots = await decodeFormationCode(importCode.trim(), queryClient);
            tbSetSlotsAction(dispatch, { slots: newSlots });
            setImportCode("");
        } catch (e) { alert("Неверный код формирования"); }
    };

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = async (event) => {
            const content = event.target?.result as string;
            try {
                if (content.trim().startsWith('{')) {
                    const json = JSON.parse(content);
                    if (json.slots) tbSetSlotsAction(dispatch, { slots: json.slots });
                } else {
                    const newSlots = await decodeFormationCode(content.trim(), queryClient);
                    tbSetSlotsAction(dispatch, { slots: newSlots });
                }
            } catch (e) { alert("Ошибка при чтении файла"); }
        };
        reader.readAsText(file);
    };

    return (
        <section className="tb-slots" onWheel={(e) => { if(layout === "line") e.stopPropagation(); }}>
            <div className="tb-slots-header" style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <span className="tb-slots-btnSlotText">Alpha v2.43</span>
                <div style={{ display: "flex", gap: "10px" }}>
                    <Toggle positionClass="tb-slots-toggle" click={handleLayoutChange} />
                    <button className="tb-slots-reset" onClick={() => tbResetAllAction(dispatch)}><XMarkSVG /> {t("TbSlots.reset")}</button>
                </div>
            </div>

            <div className="tb-slots-import-panel" style={{ display: "flex", gap: "10px", margin: "10px 0" }}>
                <input 
                    className="tb-slots-input-field"
                    style={{ flex: 1, padding: "8px 12px", borderRadius: "4px", background: "rgba(0,0,0,0.4)", border: "1px solid #444", color: "#fff" }}
                    placeholder="Team Code..."
                    value={importCode}
                    onChange={(e) => setImportCode(e.target.value)}
                />
                <button className="tb-slots-upload" style={{ whiteSpace: "nowrap" }} onClick={handleImportBtnClick}>
                    {t("TbSlots.upload")}
                </button>
            </div>

            <div className="tb-slots-actions" style={{ display: "flex", gap: "10px", margin: "10px 0", flexWrap: "wrap" }}>
                <button className="tb-slots-download" onClick={handleDownload}>{t("TbSlots.download")}</button>
                <button
                    className={`tb-slots-symmetry ${isSymmetric ? "tb-slots-symmetry--active" : ""}`}
                    aria-pressed={isSymmetric}
                    onClick={handleSymmetryChange}
                >
                    {t("TbSlots.symmetry")}
                </button>
                
                <input type="file" ref={fileInputRef} style={{ display: "none" }} onChange={handleFileUpload} />
                <button className="tb-slots-preset" onClick={() => setShowPresets(!showPresets)}>{t("TbSlots.presets")} {showPresets ? '▲' : '▼'}</button>
                
                {/* КНОПКА СОХРАНЕНИЯ ПРЕСЕТА */}
                <button className="tb-slots-save-preset" onClick={() => {
                    const name = prompt("Name:");
                    if (name) {
                        // Создаем копию текущих слотов, чтобы пресет не менялся при изменении активной команды
                        const slotsCopy = JSON.parse(JSON.stringify(slots));
                        setPresets([...presets, { id: Date.now().toString(), name, data: { slots: slotsCopy } }]);
                    }
                }}>{t("TbSlots.savePreset")}</button>
            </div>

            {showPresets && (
                <div className="tb-presets-list">
                    {presets.length === 0 && <div style={{padding: '10px', opacity: 0.5}}>No presets saved</div>}
                    {presets.map(p => (
                        <div key={p.id} className="tb-preset-item" onClick={() => tbSetSlotsAction(dispatch, { slots: p.data.slots })}>
                            <span>{p.name}</span>
                            <button className="tb-preset-delete" onClick={(e) => { 
                                e.stopPropagation(); 
                                if(window.confirm("Delete preset?")) {
                                    setPresets(presets.filter(pr => pr.id !== p.id));
                                }
                            }}>🗑</button>
                        </div>
                    ))}
                </div>
            )}

            <div style={{ position: 'relative' }}>
                <button className={`tb-slots-btnLeft ${layout === "grid" ? "hidden" : ""}`} onClick={() => containerRef.current?.scrollBy({ left: -280, behavior: "smooth" })}><ArrowLeftSVG /></button>
                <button className={`tb-slots-btnRight ${layout === "grid" ? "hidden" : ""}`} onClick={() => containerRef.current?.scrollBy({ left: 280, behavior: "smooth" })}><ArrowRightSVG /></button>
                <div 
                    className={`tb-slots-container ${animatedClass} ${isSymmetric ? "tb-slots-container--symmetric" : ""} ${isHovering && layout === "line" ? "tb-slots-container--gloving" : ""}`}
                    ref={containerRef}
                    onWheel={(e) => { if(layout === "line") containerRef.current!.scrollLeft += e.deltaY }}
                >
                    {slots.map((slot, index) => <TbSlot slot={slot} index={index} key={"slot-" + index} />)}
                </div>
            </div>
        </section>
    );
};
