import React, { useEffect } from "react";
import { Routes, Route, useLocation, Navigate } from "react-router-dom";
import { useDispatch } from "react-redux";

// Импорт всех страниц
import { IndexPage } from "../pages/IndexPage";
import { TierListPage } from "../pages/TierListPage";
import { EGOsPage } from "../pages/EGOsPage";
import { EGOPage } from "../pages/EGOPage";
import { IdentitiesPage } from "../pages/IdentitiesPage";
import { IdentityPage } from "../pages/IdentityPage";
import { TeamBuilderPage } from "../pages/TeamBuilderPage";
import { StatusesPage } from "../pages/StatusesPage";
import { ContactPage } from "../pages/ContactPage";
import { AdminPage } from "../pages/AdminPage";
import { TierListPageRedirect } from "../pages/TierListPageRedirect";
import { GratitudePage } from "../pages/GratitudePage";
import { MirrorDungeonPage } from "../pages/MirrorDungeonPage";
import { MirrorDungeonPageRedirect } from "../pages/MirrorDungeonPageRedirect";
import { EventEditorPage } from "../pages/EventEditorPage";
import { GuidesPage } from "../pages/GuidesPage";
import { GuidePage } from "../pages/GuidePage";

// Экшены
import { filterResetAllAction } from "../store/reducers/filter-reducer";
import { searchChangeValueAction } from "../store/reducers/search-reducer";

export const LimbusRouter: React.FC = () => {
    const dispatch = useDispatch();
    const location = useLocation();

    useEffect(() => {
        window.scrollTo(0, 0);
        filterResetAllAction(dispatch);
        searchChangeValueAction(dispatch, "");
    }, [location, dispatch]);

    return (
        <Routes>
            <Route path=":lang">
                {/* 1. Главная */}
                <Route index element={<IndexPage />} />

                {/* 2. Личности */}
                <Route path="identities">
                    <Route index element={<IdentitiesPage />} />
                    <Route path=":identityId" element={<IdentityPage />} />
                </Route>

                {/* 3. EGO */}
                <Route path="ego">
                    <Route index element={<EGOsPage />} />
                    <Route path=":egoId" element={<EGOPage />} />
                </Route>

                {/* 4. Тир-листы */}
                <Route path="tierlist">
                    <Route index element={<TierListPageRedirect />} />
                    <Route path=":type" element={<TierListPage />} />
                </Route>

                {/* 5. Гайды */}
                <Route path="guides">
                    <Route index element={<GuidesPage />} />
                    <Route path=":guideId" element={<GuidePage />} />
                </Route>

                {/* 6. Зеркальное подземелье */}
                <Route path="mirror-dungeon">
                    <Route index element={<MirrorDungeonPageRedirect />} />
                    <Route path=":type" element={<MirrorDungeonPage />} />
                </Route>

                {/* 7. Тесты и Админка */}
                <Route path="test">
                    <Route path="description" element={<AdminPage />} />
                    <Route path="event" element={<EventEditorPage />} />
                </Route>

                {/* 8. Остальные одиночные страницы */}
                <Route path="teambuilder" element={<TeamBuilderPage />} />
                <Route path="statuses" element={<StatusesPage />} />
                <Route path="contact" element={<ContactPage />} />
                <Route path="gratitude" element={<GratitudePage />} />
                <Route path="graditude" element={<Navigate to="../gratitude" replace />} />
            </Route>

            {/* Редирект с чистого /limbus на /limbus/en */}
            <Route path="/" element={<Navigate to="en/" replace />} />
            
            {/* Обработка ошибок внутри /limbus/ */}
            <Route path="*" element={<Navigate to="en/" replace />} />
        </Routes>
    );
};
