// Путь к файлу: src/tools/getStatusesEntityList.ts

export const getStatusesEntityList = (texts: (string | undefined | null)[]) => {
    const foundStatuses: { [key: string]: number } = {};
    
    // Новое регулярное выражение: 
    // Находит текст между # #, при этом отделяет ID от содержимого в фигурных скобках { }
    const regex = /#([^#\s{}]+)(?:\{[^}]*\})?#/g;

    texts.forEach(text => {
        if (!text || typeof text !== 'string') return;

        let match;
        // Сбрасываем индекс поиска для безопасности
        regex.lastIndex = 0; 

        while ((match = regex.exec(text)) !== null) {
            // match[1] — это чистый ID статуса (например, "burn" из тега #burn{огнем}#)
            const statusId = match[1];
            
            if (statusId) {
                // Увеличиваем счетчик или ставим 1
                foundStatuses[statusId] = (foundStatuses[statusId] || 0) + 1;
            }
        }
    });

    return foundStatuses;
};